import React, { useState, useEffect } from 'react';
import { Save, RotateCcw, Play, Download, Upload, Palette } from 'lucide-react';

interface KeyPosition {
  row: number;
  col: number;
  char: string;
  finger: string;
}

interface LayoutStats {
  effort?: number;
  distance?: number;
  same_finger_bigrams_pct?: number;
  roll_in_pct?: number;
  roll_out_pct?: number;
  trigram_alt_pct?: number;
}

const DesignerPage: React.FC = () => {
  const [layoutName, setLayoutName] = useState('My Custom Layout');
  const [layoutDescription, setLayoutDescription] = useState('A custom keyboard layout');
  const [currentLayout, setCurrentLayout] = useState<Record<string, string>>({});
  const [selectedKey, setSelectedKey] = useState<string | null>(null);
  const [stats, setStats] = useState<LayoutStats | null>(null);
  const [isAnalyzing, setIsAnalyzing] = useState(false);
  const [isSaving, setIsSaving] = useState(false);
  const [saveMessage, setSaveMessage] = useState('');

  // Default QWERTY layout for reference
  const defaultQwerty = {
    'q': 'q', 'w': 'w', 'e': 'e', 'r': 'r', 't': 't', 'y': 'y', 'u': 'u', 'i': 'i', 'o': 'o', 'p': 'p',
    'a': 'a', 's': 's', 'd': 'd', 'f': 'f', 'g': 'g', 'h': 'h', 'j': 'j', 'k': 'k', 'l': 'l', ';': ';',
    'z': 'z', 'x': 'x', 'c': 'c', 'v': 'v', 'b': 'b', 'n': 'n', 'm': 'm', ',': ',', '.': '.', '/': '/'
  };

  const keyboardLayout = [
    ['q', 'w', 'e', 'r', 't', 'y', 'u', 'i', 'o', 'p'],
    ['a', 's', 'd', 'f', 'g', 'h', 'j', 'k', 'l', ';'],
    ['z', 'x', 'c', 'v', 'b', 'n', 'm', ',', '.', '/']
  ];

  const fingerColors: Record<string, string> = {
    'LP': 'bg-red-200 dark:bg-red-800',    // Left Pinky
    'LR': 'bg-orange-200 dark:bg-orange-800', // Left Ring
    'LM': 'bg-yellow-200 dark:bg-yellow-800', // Left Middle
    'LI': 'bg-green-200 dark:bg-green-800',   // Left Index
    'RI': 'bg-blue-200 dark:bg-blue-800',    // Right Index
    'RM': 'bg-indigo-200 dark:bg-indigo-800', // Right Middle
    'RR': 'bg-purple-200 dark:bg-purple-800', // Right Ring
    'RP': 'bg-pink-200 dark:bg-pink-800'     // Right Pinky
  };

  const fingerMap: Record<string, string> = {
    'q': 'LP', 'w': 'LR', 'e': 'LM', 'r': 'LI', 't': 'LI',
    'y': 'RI', 'u': 'RI', 'i': 'RM', 'o': 'RR', 'p': 'RP',
    'a': 'LP', 's': 'LR', 'd': 'LM', 'f': 'LI', 'g': 'LI',
    'h': 'RI', 'j': 'RI', 'k': 'RM', 'l': 'RR', ';': 'RP',
    'z': 'LP', 'x': 'LR', 'c': 'LM', 'v': 'LI', 'b': 'LI',
    'n': 'RI', 'm': 'RI', ',': 'RM', '.': 'RR', '/': 'RP'
  };

  useEffect(() => {
    setCurrentLayout(defaultQwerty);
  }, []);

  useEffect(() => {
    if (Object.keys(currentLayout).length > 0) {
      analyzeLayout();
    }
  }, [currentLayout]);

  const handleKeyClick = (keyPosition: string) => {
    if (selectedKey === keyPosition) {
      setSelectedKey(null);
    } else {
      setSelectedKey(keyPosition);
    }
  };

  const handleCharacterInput = (e: React.ChangeEvent<HTMLInputElement>) => {
    if (!selectedKey) return;
    
    const newChar = e.target.value.toLowerCase().slice(-1) || selectedKey;
    setCurrentLayout(prev => ({
      ...prev,
      [selectedKey]: newChar
    }));
  };

  const analyzeLayout = async () => {
    setIsAnalyzing(true);
    try {
      const response = await fetch('/api/analyze', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ layout_data: { keys: currentLayout } }),
      });
      
      if (response.ok) {
        const data = await response.json();
        setStats(data);
      } else {
        // Fallback to mock analysis
        setStats({
          effort: 1.25,
          distance: 1.1,
          same_finger_bigrams_pct: 2.4,
          roll_in_pct: 15.8,
          roll_out_pct: 7.2,
          trigram_alt_pct: 24.6
        });
      }
    } catch (error) {
      console.error('Error analyzing layout:', error);
      // Mock stats for demonstration
      setStats({
        effort: 1.25,
        distance: 1.1,
        same_finger_bigrams_pct: 2.4,
        roll_in_pct: 15.8,
        roll_out_pct: 7.2,
        trigram_alt_pct: 24.6
      });
    } finally {
      setIsAnalyzing(false);
    }
  };

  const saveLayout = async () => {
    setIsSaving(true);
    setSaveMessage('');
    
    try {
      const layoutData = {
        name: layoutName,
        slug: layoutName.toLowerCase().replace(/[^a-z0-9]/g, '-'),
        type: 'custom',
        description: layoutDescription,
        visual_data: { keys: currentLayout },
        file_formats: {}
      };
      
      const response = await fetch('/api/layouts', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify(layoutData),
      });
      
      if (response.ok) {
        setSaveMessage('Layout saved successfully!');
      } else {
        setSaveMessage('Error saving layout. Please try again.');
      }
    } catch (error) {
      console.error('Error saving layout:', error);
      setSaveMessage('Error saving layout. Please try again.');
    } finally {
      setIsSaving(false);
    }
  };

  const resetLayout = () => {
    setCurrentLayout(defaultQwerty);
    setSelectedKey(null);
    setLayoutName('My Custom Layout');
    setLayoutDescription('A custom keyboard layout');
    setSaveMessage('');
  };

  const exportLayout = () => {
    const layoutData = {
      name: layoutName,
      description: layoutDescription,
      layout: currentLayout,
      stats: stats,
      created: new Date().toISOString()
    };
    
    const blob = new Blob([JSON.stringify(layoutData, null, 2)], { type: 'application/json' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `${layoutName.replace(/[^a-z0-9]/gi, '_')}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const importLayout = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;
    
    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const data = JSON.parse(event.target?.result as string);
        if (data.layout) {
          setCurrentLayout(data.layout);
          setLayoutName(data.name || 'Imported Layout');
          setLayoutDescription(data.description || 'An imported keyboard layout');
        }
      } catch (error) {
        console.error('Error importing layout:', error);
      }
    };
    reader.readAsText(file);
  };

  const getMetricColor = (value: number | undefined, good: number, bad: number, lowerIsBetter: boolean = true) => {
    if (value === undefined) return 'text-gray-400';
    if (lowerIsBetter) {
      return value <= good ? 'text-green-500' : value >= bad ? 'text-red-500' : 'text-yellow-500';
    } else {
      return value >= good ? 'text-green-500' : value <= bad ? 'text-red-500' : 'text-yellow-500';
    }
  };

  return (
    <div className="min-h-screen bg-gray-50 dark:bg-gray-900 py-8">
      <div className="max-w-7xl mx-auto px-4">
        {/* Header */}
        <div className="text-center mb-8">
          <h1 className="text-4xl font-bold bg-gradient-to-r from-purple-600 to-blue-600 bg-clip-text text-transparent mb-4">
            Layout Designer
          </h1>
          <p className="text-gray-600 dark:text-gray-300 max-w-2xl mx-auto">
            Create and customize your own keyboard layout. Click on keys to modify them and see real-time analysis.
          </p>
        </div>

        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          {/* Layout Designer */}
          <div className="lg:col-span-2">
            <div className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-lg">
              <div className="flex items-center justify-between mb-6">
                <h2 className="text-2xl font-bold">Design Your Layout</h2>
                <div className="flex items-center gap-2">
                  <Palette className="text-purple-600" size={20} />
                  <span className="text-sm text-gray-600 dark:text-gray-400">Click keys to edit</span>
                </div>
              </div>

              {/* Keyboard */}
              <div className="space-y-2 mb-6">
                {keyboardLayout.map((row, rowIndex) => (
                  <div key={rowIndex} className="flex justify-center gap-1">
                    {row.map((keyPos, colIndex) => {
                      const finger = fingerMap[keyPos];
                      const isSelected = selectedKey === keyPos;
                      return (
                        <button
                          key={keyPos}
                          onClick={() => handleKeyClick(keyPos)}
                          className={`
                            w-12 h-12 rounded-lg border-2 font-mono font-bold text-lg
                            transition-all duration-200 hover:scale-105
                            ${
                              isSelected
                                ? 'border-purple-500 bg-purple-100 dark:bg-purple-900 shadow-lg'
                                : `border-gray-300 dark:border-gray-600 ${fingerColors[finger]}`
                            }
                          `}
                        >
                          {currentLayout[keyPos] || keyPos}
                        </button>
                      );
                    })}
                  </div>
                ))}
              </div>

              {/* Character Input */}
              {selectedKey && (
                <div className="bg-purple-50 dark:bg-purple-900/20 rounded-lg p-4 mb-6">
                  <label className="block text-sm font-medium mb-2">
                    Edit key '{selectedKey}' (currently: '{currentLayout[selectedKey]}')
                  </label>
                  <input
                    type="text"
                    value={currentLayout[selectedKey] || ''}
                    onChange={handleCharacterInput}
                    className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                    placeholder="Enter character"
                    maxLength={1}
                  />
                </div>
              )}

              {/* Controls */}
              <div className="flex flex-wrap gap-3">
                <button
                  onClick={analyzeLayout}
                  disabled={isAnalyzing}
                  className="flex items-center gap-2 bg-purple-600 hover:bg-purple-700 disabled:bg-purple-400 text-white px-4 py-2 rounded-lg transition-colors"
                >
                  <Play size={16} />
                  {isAnalyzing ? 'Analyzing...' : 'Analyze'}
                </button>
                <button
                  onClick={saveLayout}
                  disabled={isSaving}
                  className="flex items-center gap-2 bg-green-600 hover:bg-green-700 disabled:bg-green-400 text-white px-4 py-2 rounded-lg transition-colors"
                >
                  <Save size={16} />
                  {isSaving ? 'Saving...' : 'Save Layout'}
                </button>
                <button
                  onClick={resetLayout}
                  className="flex items-center gap-2 bg-gray-600 hover:bg-gray-700 text-white px-4 py-2 rounded-lg transition-colors"
                >
                  <RotateCcw size={16} />
                  Reset
                </button>
                <button
                  onClick={exportLayout}
                  className="flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-4 py-2 rounded-lg transition-colors"
                >
                  <Download size={16} />
                  Export
                </button>
                <label className="flex items-center gap-2 bg-orange-600 hover:bg-orange-700 text-white px-4 py-2 rounded-lg transition-colors cursor-pointer">
                  <Upload size={16} />
                  Import
                  <input
                    type="file"
                    accept=".json"
                    onChange={importLayout}
                    className="hidden"
                  />
                </label>
              </div>

              {saveMessage && (
                <div className={`mt-4 p-3 rounded-lg ${
                  saveMessage.includes('successfully') 
                    ? 'bg-green-100 text-green-700 dark:bg-green-900 dark:text-green-300'
                    : 'bg-red-100 text-red-700 dark:bg-red-900 dark:text-red-300'
                }`}>
                  {saveMessage}
                </div>
              )}
            </div>
          </div>

          {/* Layout Info & Stats */}
          <div className="space-y-6">
            {/* Layout Information */}
            <div className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-lg">
              <h3 className="text-xl font-bold mb-4">Layout Information</h3>
              <div className="space-y-4">
                <div>
                  <label className="block text-sm font-medium mb-2">Layout Name</label>
                  <input
                    type="text"
                    value={layoutName}
                    onChange={(e) => setLayoutName(e.target.value)}
                    className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                  />
                </div>
                <div>
                  <label className="block text-sm font-medium mb-2">Description</label>
                  <textarea
                    value={layoutDescription}
                    onChange={(e) => setLayoutDescription(e.target.value)}
                    rows={3}
                    className="w-full p-3 border border-gray-300 rounded-lg focus:ring-2 focus:ring-purple-500 focus:border-transparent"
                  />
                </div>
              </div>
            </div>

            {/* Live Analysis */}
            {stats && (
              <div className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-lg">
                <h3 className="text-xl font-bold mb-4">Live Analysis</h3>
                <div className="space-y-3">
                  <div className="flex justify-between items-center">
                    <span className="text-sm">Effort</span>
                    <span className={`font-bold ${getMetricColor(stats.effort, 1.2, 1.4)}`}>
                      {stats.effort?.toFixed(2) || 'N/A'}
                    </span>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-sm">Distance</span>
                    <span className={`font-bold ${getMetricColor(stats.distance, 1.0, 1.5)}`}>
                      {stats.distance?.toFixed(2) || 'N/A'}
                    </span>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-sm">Same Finger Bigrams</span>
                    <span className={`font-bold ${getMetricColor(stats.same_finger_bigrams_pct, 2, 5)}`}>
                      {stats.same_finger_bigrams_pct?.toFixed(1)}%
                    </span>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-sm">Roll In</span>
                    <span className={`font-bold ${getMetricColor(stats.roll_in_pct, 15, 8, false)}`}>
                      {stats.roll_in_pct?.toFixed(1)}%
                    </span>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-sm">Roll Out</span>
                    <span className={`font-bold ${getMetricColor(stats.roll_out_pct, 12, 6, false)}`}>
                      {stats.roll_out_pct?.toFixed(1)}%
                    </span>
                  </div>
                  <div className="flex justify-between items-center">
                    <span className="text-sm">Alternation</span>
                    <span className={`font-bold ${getMetricColor(stats.trigram_alt_pct, 25, 15, false)}`}>
                      {stats.trigram_alt_pct?.toFixed(1)}%
                    </span>
                  </div>
                </div>
              </div>
            )}

            {/* Finger Map Legend */}
            <div className="bg-white dark:bg-gray-800 rounded-xl p-6 shadow-lg">
              <h3 className="text-xl font-bold mb-4">Finger Assignment</h3>
              <div className="grid grid-cols-2 gap-2 text-sm">
                <div className="flex items-center gap-2">
                  <div className="w-4 h-4 rounded bg-red-200 dark:bg-red-800"></div>
                  <span>Left Pinky</span>
                </div>
                <div className="flex items-center gap-2">
                  <div className="w-4 h-4 rounded bg-orange-200 dark:bg-orange-800"></div>
                  <span>Left Ring</span>
                </div>
                <div className="flex items-center gap-2">
                  <div className="w-4 h-4 rounded bg-yellow-200 dark:bg-yellow-800"></div>
                  <span>Left Middle</span>
                </div>
                <div className="flex items-center gap-2">
                  <div className="w-4 h-4 rounded bg-green-200 dark:bg-green-800"></div>
                  <span>Left Index</span>
                </div>
                <div className="flex items-center gap-2">
                  <div className="w-4 h-4 rounded bg-blue-200 dark:bg-blue-800"></div>
                  <span>Right Index</span>
                </div>
                <div className="flex items-center gap-2">
                  <div className="w-4 h-4 rounded bg-indigo-200 dark:bg-indigo-800"></div>
                  <span>Right Middle</span>
                </div>
                <div className="flex items-center gap-2">
                  <div className="w-4 h-4 rounded bg-purple-200 dark:bg-purple-800"></div>
                  <span>Right Ring</span>
                </div>
                <div className="flex items-center gap-2">
                  <div className="w-4 h-4 rounded bg-pink-200 dark:bg-pink-800"></div>
                  <span>Right Pinky</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default DesignerPage;
